// app/core/simulation-command.ts
var SimulationCommand = class {
  constructor(delay) {
    this.executed = false;
    this.delay = delay;
  }
  execute() {
  }
  update(dt) {
    this.delay -= dt;
    if (this.delay < 0) {
      this.execute();
      this.executed = true;
    }
  }
};
var DelayedCommand = class extends SimulationCommand {
  constructor(delayedFunction, delay) {
    super(delay);
    this.delayedFunction = delayedFunction;
  }
  execute() {
    super.execute();
    this.delayedFunction();
  }
};
var AttackCommand = class extends SimulationCommand {
  constructor(delay, pokemon, target, board) {
    super(delay);
    this.pokemon = pokemon;
    this.board = board;
    this.target = target;
  }
  execute() {
    if (this.pokemon.canAttack) {
      this.pokemon.state.attack(this.pokemon, this.board, this.target);
    }
  }
};

