console.time("precompute-types-and-categories");
var data3 = {};
precomputedPokemonsImplemented.forEach((pokemon) => {
  pokemon.types.forEach((type18) => {
    if (type18 in data3 === false) {
      data3[type18] = {
        pokemons: [],
        uniquePokemons: [],
        legendaryPokemons: [],
        additionalPokemons: [],
        specialPokemons: []
      };
    }
    if (pokemon.rarity === "UNIQUE" /* UNIQUE */) {
      data3[type18].uniquePokemons.push(pokemon.name);
    } else if (pokemon.rarity === "LEGENDARY" /* LEGENDARY */) {
      data3[type18].legendaryPokemons.push(pokemon.name);
    } else if (pokemon.rarity === "SPECIAL" /* SPECIAL */) {
      data3[type18].specialPokemons.push(pokemon.name);
    } else if (pokemon.additional) {
      if (!data3[type18].additionalPokemons.some(
        (p) => PkmFamily[p] === PkmFamily[pokemon.name]
      )) {
        data3[type18].additionalPokemons.push(pokemon.name);
      }
    } else if (!data3[type18].pokemons.some(
      (p) => PkmFamily[p] === PkmFamily[pokemon.name]
    )) {
      data3[type18].pokemons.push(pokemon.name);
    }
  });
});
var PRECOMPUTED_POKEMONS_PER_TYPE_AND_CATEGORY = data3;
console.timeEnd("precompute-types-and-categories");

