    const damage = pokemon.stars === 3 ? 40 : pokemon.stars === 2 ? 20 : 10;
    const opponentTeam = pokemon.team === 0 /* BLUE_TEAM */ ? 1 /* RED_TEAM */ : 0 /* BLUE_TEAM */;
