var MountainGaleStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit, true);
    const damage = [20, 40, 80][pokemon.stars - 1] ?? 80;
    const targets = board.getAdjacentCells(pokemon.positionX, pokemon.positionY, false).filter((cell) => cell.value && cell.value.team !== pokemon.team).map((cell) => cell.value);
    if (targets.length === 0 || !targets.some((t) => t.id === target.id)) {
      targets.push(target);
    }
    const nbHits = [1, 3, 3][pokemon.stars - 1] ?? 3;
    const nbBergmites = pokemon.count.ult === 0 ? max(MaxTroopersPerPkm[pokemon.name] ?? 0)(
      [...pokemon.effectsSet.values()].find(
        (e) => e instanceof BergmiteOnBackEffect
      )?.stacks ?? 0
    ) : 0;
    for (let i = 0; i < nbHits + nbBergmites; i++) {
      const t = pickRandomIn(targets);
      pokemon.commands.push(
        new DelayedCommand(() => {
          t.status.triggerFlinch(3e3, pokemon);
          t.handleSpecialDamage(
            damage,
            board,
            1 /* SPECIAL */,
            pokemon,
            crit
          );
          pokemon.broadcastAbility({
            targetX: t.positionX,
            targetY: t.positionY,
            delay: i >= nbHits ? i - nbHits : void 0
          });
        }, 200 * i)
      );
    }
  }
};
var TwineedleStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit, true);
    const damage = [25, 50, 80][pokemon.stars - 1] ?? 80;
    target.handleSpecialDamage(
      damage,
      board,
      1 /* SPECIAL */,
      pokemon,
      chance(pokemon.critChance / 100, pokemon)
    );
    pokemon.commands.push(
      new DelayedCommand(() => {
        target.handleSpecialDamage(
          damage,
          board,
          1 /* SPECIAL */,
          pokemon,
          crit
        );
        if (chance(0.5, pokemon)) {
          target.status.triggerPoison(4e3, target, pokemon);
        }
      }, 500)
    );
  }
};
var RockWreckerStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit);
    const damage = [80, 160][pokemon.stars - 1] ?? 160;
    target.status.triggerFlinch(2e3, pokemon);
    target.handleSpecialDamage(damage, board, 1 /* SPECIAL */, pokemon, crit);
    pokemon.status.triggerFatigue(4e3, pokemon);
  }
};
var SnoreStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit);
    const damage = [20, 40, 60][pokemon.stars - 1] ?? 70;
    const targets = board.getCellsInFront(pokemon, target).filter((cell) => cell.value && cell.value.team !== pokemon.team);
    for (const cell of targets) {
      if (cell.value) {
        cell.value.status.triggerFlinch(3e3, pokemon);
        cell.value.handleSpecialDamage(
          damage,
          board,
          1 /* SPECIAL */,
          pokemon,
          crit
        );
      }
    }
  }
};
var StuffCheeksStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit);
    const heldBerry = pickRandomIn(
      schemaValues(pokemon.items).filter((item) => isIn(Berries, item))
    );
    if (heldBerry) {
      pokemon.eatBerry(heldBerry, void 0, true, pokemon.ap / 100, crit);
    } else {
      const berry = pickRandomIn(NonSpecialBerries);
      pokemon.addItem(berry, true);
    }
  }
};
var AquaStepStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit, true);
    const damage = [25, 50, 100][pokemon.stars - 1] ?? 100;
    const speedGain = [10, 15, 20][pokemon.stars - 1] ?? 20;
    const dx = target.positionX - pokemon.positionX;
    const dy = target.positionY - pokemon.positionY;
    const stepCell = board.getClosestAvailablePlace(
      pokemon.positionX + Math.sign(dx),
      pokemon.positionY + Math.sign(dy)
    );
    if (stepCell) {
      pokemon.moveTo(stepCell.x, stepCell.y, board, false);
    }
    pokemon.commands.push(
      new DelayedCommand(() => {
        pokemon.broadcastAbility({
          targetX: target.positionX,
          targetY: target.positionY
        });
        target.handleSpecialDamage(
          damage,
          board,
          1 /* SPECIAL */,
          pokemon,
          crit
        );
        pokemon.addSpeed(speedGain, pokemon, 1, true);
      }, 300)
    );
  }
};
var SkitterSmackStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit, true);
    const damage = [15, 30, 60][pokemon.stars - 1] ?? 60;
    pokemon.orientation = board.orientation(
      pokemon.positionX,
      pokemon.positionY,
      target.positionX,
      target.positionY,
      pokemon,
      target
    );
    const [dx, dy] = OrientationVector[pokemon.orientation];
    const nextX = target.positionX + dx;
    const nextY = target.positionY + dy;
    const behindCell = board.getClosestAvailablePlace(nextX, nextY);
    if (behindCell) {
      pokemon.moveTo(behindCell.x, behindCell.y, board, true);
    }
    pokemon.commands.push(
      new DelayedCommand(() => {
        if (target.hp > 0) {
          target.handleSpecialDamage(
            damage,
            board,
            1 /* SPECIAL */,
            pokemon,
            crit
          );
          target.addAbilityPower(-20, pokemon, 0, false);
        }
      }, 300)
    );
  }
};
var SilkTrapStrategy = class extends AbilityStrategy {
  process(pokemon, board, target, crit) {
    super.process(pokemon, board, target, crit);
    const speedNerf = [5, 10, 15][pokemon.stars - 1] ?? 15;
    const trapEffect = new OnAttackReceivedEffect(({ attacker, pokemon: pokemon2 }) => {
      if (distanceC(
        attacker.positionX,
        attacker.positionY,
        pokemon2.positionX,
        pokemon2.positionY
      ) === 1) {
        attacker.addSpeed(-speedNerf, pokemon2, 1, crit);
        attacker.status.triggerParalysis(1500, attacker, pokemon2);
      }
    });
    pokemon.status.triggerProtect(1500);
    pokemon.effectsSet.add(trapEffect);
    pokemon.commands.push(
      new DelayedCommand(() => {
        pokemon.effectsSet.delete(trapEffect);
      }, 1500)
    );
  }
};
