var MonsterKillEffect = class extends OnKillEffect {
  constructor(effect) {
    super(void 0, effect);
    this.hpBoosted = 0;
    this.count = 0;
    this.synergyLevel = SynergyEffects["MONSTER" /* MONSTER */].indexOf(effect);
  }
  apply({ attacker, target }) {
    const attackBoost = MONSTER_ATTACK_BUFF_PER_SYNERGY_LEVEL[this.synergyLevel] ?? MONSTER_ATTACK_BUFF_PER_SYNERGY_LEVEL.at(-1);
    const apBoost = MONSTER_AP_BUFF_PER_SYNERGY_LEVEL[this.synergyLevel] ?? MONSTER_AP_BUFF_PER_SYNERGY_LEVEL.at(-1);
    const hpGain = MONSTER_MAX_HP_BUFF_FACTOR_PER_SYNERGY_LEVEL[this.synergyLevel] ?? MONSTER_MAX_HP_BUFF_FACTOR_PER_SYNERGY_LEVEL.at(-1);
    const lifeBoost = hpGain * target.maxHP;
    attacker.addAttack(attackBoost, attacker, 0, false);
    attacker.addAbilityPower(apBoost, attacker, 0, false);
    attacker.addMaxHP(lifeBoost, attacker, 0, false);
    this.hpBoosted += lifeBoost;
    this.count += 1;
    if (attacker.items.has("BERSERK_GENE" /* BERSERK_GENE */)) {
      attacker.status.triggerConfusion(1e3, attacker, attacker);
    }
  }
};
var GroundHoleEffect = class extends OnSpawnEffect {
  constructor(effect) {
    const synergyLevel = SynergyEffects["GROUND" /* GROUND */].indexOf(effect) + 1;
    super((pokemon, player) => {
      const y = player?.team === 1 /* RED_TEAM */ ? BOARD_HEIGHT - 1 - pokemon.positionY : pokemon.positionY;
      const index = y * BOARD_WIDTH + pokemon.positionX;
      const holeLevel = player?.groundHoles[index] ?? 0;
      let defBuff = holeLevel * [0, 1, 2, 3, 3][synergyLevel];
      let atkBuff = holeLevel === 5 ? [0, 3, 5, 8, 8][synergyLevel] : 0;
      if (synergyLevel === 4) {
        const nbFullyDugRows = [0, 8, 16].reduce((count2, startIdx) => {
          const row = player?.groundHoles.slice(startIdx, startIdx + 8) ?? [];
          return count2 + (row.every((hole) => hole === 5) ? 1 : 0);
        }, 0);
        defBuff += nbFullyDugRows * 5;
        if (nbFullyDugRows === 3) {
          atkBuff += 8;
          player?.titles.add("MOLE" /* MOLE */);
        }
      }
      pokemon.addAttack(atkBuff, pokemon, 0, false);
      pokemon.addDefense(defBuff, pokemon, 0, false);
      pokemon.addSpecialDefense(defBuff, pokemon, 0, false);
      pokemon.broadcastAbility({ skill: "GROUND_GROW" });
    });
  }
};
var FireHitEffect = class extends OnAttackEffect {
  constructor(effect) {
    super(void 0, effect);
    this.count = 0;
    this.synergyLevel = SynergyEffects["FIRE" /* FIRE */].indexOf(effect);
  }
  apply({ pokemon }) {
    pokemon.addAttack(this.synergyLevel, pokemon, 0, false);
    this.count += 1;
  }
};
