var DojoTicketOnItemDroppedEffect = class extends OnItemDroppedEffect {
  constructor(ticketLevel) {
    super(({ pokemon, player, room, item }) => {
      if (NonPkm.includes(pokemon.name)) return false;
      const baseline = getPokemonBaseline(pokemon.name);
      if (player.dojoFamilies.includes(baseline)) return false;
      const hpBonus = [50, 100, 150][ticketLevel - 1] ?? 0;
      const atkBonus = [5, 10, 15][ticketLevel - 1] ?? 0;
      const apBonus = [15, 30, 45][ticketLevel - 1] ?? 0;
      pokemon.addMaxHP(hpBonus);
      pokemon.addAttack(atkBonus);
      pokemon.addAbilityPower(apBonus);
      player.dojoFamilies.push(baseline);
      removeInArray(player.items, item);
      return false;
    });
  }
};
var chefCookEffect = new OnStageStartEffect(({ pokemon, player, room }) => {
  if (!pokemon) return;
  const chef = pokemon;
  const gourmetLevel = getSynergyStep(player.synergies, "GOURMET" /* GOURMET */);
  const nbDishes = [0, 1, 2, 2][gourmetLevel] ?? 2;
  let dish = DishByPkm[chef.name];
  if (chef.items.has("COOKING_POT" /* COOKING_POT */)) {
    dish = "HEARTY_STEW" /* HEARTY_STEW */;
  } else if (chef.name.startsWith("ARCEUS") || chef.name === "KECLEON" /* KECLEON */ || chef.items.has("GOURMET_MEMORY" /* GOURMET_MEMORY */)) {
    dish = "SANDWICH" /* SANDWICH */;
  }
  if (chef.passive === "GLUTTON" /* GLUTTON */) {
    chef.addMaxHP(30);
    if (chef.maxHP > 750) {
      player.titles.add("GLUTTON" /* GLUTTON */);
    }
  }
  if (dish && nbDishes > 0) {
    let dishes = Array.from({ length: nbDishes }, () => dish);
    if (dish === "BERRIES" /* BERRIES */) {
      dishes = pickNRandomIn(
        NonSpecialBerries.filter((i) => pokemon.items.has(i) === false),
        nbDishes
      );
    }
    if (dish === "MUSHROOMS" /* MUSHROOMS */) {
      dishes = Array.from(
        { length: nbDishes },
        () => randomWeighted({
          ["TINY_MUSHROOM" /* TINY_MUSHROOM */]: 77,
          ["BIG_MUSHROOM" /* BIG_MUSHROOM */]: 20,
          ["BALM_MUSHROOM" /* BALM_MUSHROOM */]: 3
        }) ?? "TINY_MUSHROOM" /* TINY_MUSHROOM */
      );
    }
    if (dish === "SWEETS" /* SWEETS */) {
      dishes = pickNRandomIn(Sweets, nbDishes);
    }
    room.clock.setTimeout(async () => {
      room.broadcast("COOK" /* COOK */, {
        pokemonId: chef.id,
        dishes
      });
      room.clock.setTimeout(() => {
        dishes.forEach((dish2, i) => {
          if (pokemon.name === "SKWOVET" /* SKWOVET */ || pokemon.name === "GREEDENT" /* GREEDENT */) {
            if (pokemon.items.size < 3) {
              pokemon.addItem(dish2, player);
            } else {
              player.items.push(dish2);
            }
          } else if (isIn(DishesGoingToInventory, dish2)) {
            player.items.push(dish2);
          } else {
            let candidates = schemaValues(player.board).filter(
              (p) => p.canEat && !p.dishes.has(dish2) && isOnBench(chef) === isOnBench(p) && distanceC(
                chef.positionX,
                chef.positionY,
                p.positionX,
                p.positionY
              ) === 1
            );
            if (dish2 === "HERBA_MYSTICA" /* HERBA_MYSTICA */) {
              candidates = candidates.filter(
                (p) => HerbaMysticas.every((herba) => p.dishes.has(herba) === false)
              );
            }
            candidates.sort((a, b) => getUnitScore(b) - getUnitScore(a));
            const pokemon2 = candidates[0] ?? chef;
            if (!pokemon2.canEat) return;
            if (dish2 === "HERBA_MYSTICA" /* HERBA_MYSTICA */) {
              const flavors = [];
              if (pokemon2.types.has("FAIRY" /* FAIRY */))
                flavors.push("HERBA_MYSTICA_SWEET" /* HERBA_MYSTICA_SWEET */);
              if (pokemon2.types.has("PSYCHIC" /* PSYCHIC */))
                flavors.push("HERBA_MYSTICA_SPICY" /* HERBA_MYSTICA_SPICY */);
              if (pokemon2.types.has("ELECTRIC" /* ELECTRIC */))
                flavors.push("HERBA_MYSTICA_SOUR" /* HERBA_MYSTICA_SOUR */);
              if (pokemon2.types.has("GRASS" /* GRASS */))
                flavors.push("HERBA_MYSTICA_BITTER" /* HERBA_MYSTICA_BITTER */);
              if (flavors.length === 0) flavors.push("HERBA_MYSTICA_SALTY" /* HERBA_MYSTICA_SALTY */);
              dish2 = pickRandomIn(flavors);
            }
            pokemon2.dishes.add(dish2);
            pokemon2.action = "Eat" /* EAT */;
          }
        });
      }, 2e3);
    }, 1e3);
  }
});
